import { Router } from 'express';
import { approveCommittee, listAuditLogs, listUsers, updateUserRole, } from '../controllers/admin.controller.js';
import { authenticate } from '../middleware/auth.middleware.js';
import { authorize } from '../middleware/authorize.middleware.js';
import { validateRequest } from '../middleware/validate.middleware.js';
import { approveCommitteeValidator, updateUserRoleValidator } from '../validators/admin.validator.js';
export const adminRouter = Router();
adminRouter.use(authenticate, authorize('super_admin', 'admin'));
adminRouter.get('/users', listUsers);
adminRouter.patch('/users/:id', updateUserRoleValidator, validateRequest, updateUserRole);
adminRouter.patch('/committees/:id/approve', approveCommitteeValidator, validateRequest, approveCommittee);
adminRouter.get('/audit-logs', listAuditLogs);
